```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // 1. Create a buffer_adaptor from the input buffer span
    hexi::buffer_adaptor adaptor(buffer);

    // 2. Create a binary_stream using the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // 3. Preview the data_type using buffer_adaptor's operator[] without advancing read pointer
    uint8_t data_type = adaptor[0];
    result.data_type = data_type;

    // 4. Check if the buffer has enough data for the header and items
    // Header: 1 byte (data_type) + 4 bytes (item_count) = 5 bytes minimum
    // Items: item_count * 4 bytes (each item is either uint32_t or float)
    constexpr size_t header_size = 5; // data_type + item_count
    uint32_t item_count = 0;

    // Read item_count (uint32_t) from the stream
    stream >> item_count;

    // Calculate total data size needed
    size_t total_data_needed = header_size + (item_count * sizeof(uint32_t));

    // Check if buffer has enough data
    if (stream.read_max() < total_data_needed - header_size) {
        // Not enough data for the items, return empty result
        return result;
    }

    // 5. Based on data_type, read the appropriate items
    if (data_type == 0) {
        // Integers
        result.int_items.resize(item_count);
        stream.get(result.int_items);
    } else if (data_type == 1) {
        // Floats
        result.float_items.resize(item_count);
        stream.get(result.float_items);
    } else {
        // Unknown data type, return empty vectors
        return result;
    }

    return result;
}
```

