```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // 1. Create a buffer_adaptor instance from the input span
    hexi::buffer_adaptor adaptor(buffer);

    // 2. Check available data using the size() method
    if (adaptor.size() < sizeof(PacketHeader)) {
        // Handle insufficient data - return default initialized header
        return {};
    }

    // 3. Use read_ptr() to get a pointer to the current read position
    const uint8_t* read_pointer = adaptor.read_ptr();

    // 4. Create a span from the read pointer with the size of PacketHeader
    std::span<const PacketHeader> header_span(reinterpret_cast<const PacketHeader*>(read_pointer), 1);

    // 5. Access the header data through the span
    PacketHeader header = header_span[0];

    return header;
}
```

**Alternative implementation using binary_stream for zero-copy operations:**

