#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance for demonstration
    hexi::block_allocator<int, element_count> allocator;

    // Demonstrate initial state: free list contains all blocks
    // (This is handled in the constructor via initialise_free_list)

    // Allocate all blocks to exhaust the free list
    int* allocated_blocks[element_count];
    for (size_t i = 0; i < element_count; ++i) {
        allocated_blocks[i] = allocator.allocate();
        // Each allocation calls push() internally when deallocating previous blocks
        // but for first allocations, it's just taking from the pre-initialized free list
    }

    // At this point, the free list should be empty

    // Deallocate one block to demonstrate push() operation
    allocator.deallocate(allocated_blocks[0]);
    // This calls push(free_block), adding the block back to the free list

    // Allocate again to demonstrate pop() operation
    int* new_block = allocator.allocate();
    // This calls pop() to remove a block from the head of the free list

    // Deallocate the remaining blocks to clean up
    for (size_t i = 1; i < element_count; ++i) {
        allocator.deallocate(allocated_blocks[i]);
    }
    allocator.deallocate(new_block);

    // The free list management is now demonstrated through the lifecycle
}
```

