#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Check if the requested preview size is available
    size_t available_bytes = buffer.size();
    size_t preview_size = (bytes_to_preview > available_bytes) ? available_bytes : bytes_to_preview;

    // Create a destination vector with the appropriate size
    std::vector<uint8_t> preview_data(preview_size);

    // Use the copy function to copy data without advancing the read pointer
    if (preview_size > 0) {
        buffer.copy(preview_data.data(), preview_size);
    }

    return preview_data;
}
```

**Explanation:**

1. **Check available bytes**: Use `buffer.size()` to determine how many bytes are currently available in the buffer
2. **Calculate preview size**: Take the minimum of `bytes_to_preview` and available bytes to ensure we don't request more data than available
3. **Create destination vector**: Initialize a `std::vector<uint8_t>` with the calculated preview size
4. **Copy data without advancing**: Use the `copy` function from the Hexi library, which copies data without modifying the read position
5. **Return preview data**: Return the vector containing the previewed data

This implementation follows the specifications exactly, using the provided Hexi library functions while ensuring safe handling of buffer boundaries.

