};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Serialize the packet_id as a fixed-size uint32_t
    stream << packet.packet_id;

    // Serialize the tags vector using prefixed_varint adaptor
    stream << hexi::prefixed_varint{packet.tags};

    // Serialize the data string using prefixed_varint adaptor
    stream << hexi::prefixed_varint{packet.data};

    return buffer;
}

