    // Create a buffer_adaptor from the input span
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Deserialize the packet_id as a fixed-size uint32_t
    stream >> packet.packet_id;

    // Deserialize the tags vector using prefixed_varint adaptor
    stream >> hexi::prefixed_varint{packet.tags};

    // Deserialize the data string using prefixed_varint adaptor
    stream >> hexi::prefixed_varint{packet.data};

    return packet;
